constType:
∀ {M : Type u_3} [inst : Add M] (carrier carrier_1 : Set M) (e_carrier : carrier = carrier_1)
  (add_mem' : ∀ {a b : M}, a ∈ carrier → b ∈ carrier → a + b ∈ carrier),
  { carrier := carrier, add_mem' := add_mem' } = { carrier := carrier_1, add_mem' := ⋯ }

∀ {M : Type u_10} {N : Type u_11} [inst : Add M] [inst_1 : Add N] (toFun toFun_1 : M → N) (e_toFun : toFun = toFun_1)
  (map_add' : ∀ (x y : M), toFun (x + y) = toFun x + toFun y),
  { toFun := toFun, map_add' := map_add' } = { toFun := toFun_1, map_add' := ⋯ }

∀ {𝕜 : Type u_1} [inst : NontriviallyNormedField 𝕜] {E : Type u_2} [inst_1 : SeminormedAddCommGroup E]
  [inst_2 : IsUltrametricDist E] [inst_3 : NormedSpace 𝕜 E] {D : Submodule 𝕜 E} {F : Type u_3}
  [inst_4 : SeminormedAddCommGroup F] [inst_5 : IsUltrametricDist F] [inst_6 : NormedSpace 𝕜 F]
  [inst_7 : SphericallyCompleteSpace F] {S : ↥D →L[𝕜] F} {𝒰 : Set (E →L[𝕜] F)} {h𝒰 : 𝒰.Nonempty} {ε : ↑𝒰 → ℝ}
  (self : SphericallyCompleteSpace.PartialExtension✝ 𝕜 E F S 𝒰 h𝒰 ε) (x : ↥D),
  (SphericallyCompleteSpace.PartialExtension.T✝ self) ⟨↑x, ⋯⟩ = S x

∀ {R : Type u_14} {S : Type u_15} [inst : Semiring R] [inst_1 : Semiring S] {σ : R →+* S} {M : Type u_16}
  {M₂ : Type u_17} [inst_2 : AddCommMonoid M] [inst_3 : AddCommMonoid M₂] [inst_4 : _root_.Module R M]
  [inst_5 : _root_.Module S M₂] (toAddHom toAddHom_1 : M →ₙ+ M₂) (e_toAddHom : toAddHom = toAddHom_1)
  (map_smul' : ∀ (m : R) (x : M), toAddHom.toFun (m • x) = σ m • toAddHom.toFun x),
  { toAddHom := toAddHom, map_smul' := map_smul' } = { toAddHom := toAddHom_1, map_smul' := ⋯ }

∀ {𝕜 : Type u_1} [inst : NontriviallyNormedField 𝕜] {E : Type u_2} [inst_1 : SeminormedAddCommGroup E]
  [inst_2 : IsUltrametricDist E] [inst_3 : NormedSpace 𝕜 E] {D : Submodule 𝕜 E} {F : Type u_3}
  [inst_4 : SeminormedAddCommGroup F] [inst_5 : IsUltrametricDist F] [inst_6 : NormedSpace 𝕜 F]
  [inst_7 : SphericallyCompleteSpace F] {S : ↥D →L[𝕜] F} {𝒰 : Set (E →L[𝕜] F)} {h𝒰 : 𝒰.Nonempty} {ε : ↑𝒰 → ℝ}
  (self : SphericallyCompleteSpace.PartialExtension✝ 𝕜 E F S 𝒰 h𝒰 ε),
  D ≤ SphericallyCompleteSpace.PartialExtension.M✝ self

∀ {R : Type u_1} {S : Type u_2} [inst : Semiring R] [inst_1 : Semiring S] {σ : R →+* S} {M : Type u_3}
  [inst_2 : TopologicalSpace M] [inst_3 : AddCommMonoid M] {M₂ : Type u_4} [inst_4 : TopologicalSpace M₂]
  [inst_5 : AddCommMonoid M₂] [inst_6 : _root_.Module R M] [inst_7 : _root_.Module S M₂]
  (toLinearMap toLinearMap_1 : M →ₛₗ[σ] M₂) (e_toLinearMap : toLinearMap = toLinearMap_1)
  (cont : Continuous toLinearMap.toFun),
  { toLinearMap := toLinearMap, cont := cont } = { toLinearMap := toLinearMap_1, cont := ⋯ }

∀ (𝕜 : Type u_2) [inst : NontriviallyNormedField 𝕜] (E : ℕ → Type u_1) [inst_1 : (i : ℕ) → NormedAddCommGroup (E i)]
  [inst_2 : (i : ℕ) → NormedSpace 𝕜 (E i)] (c : 𝕜) {x : ↥(lp E ⊤)},
  x ∈ {f | ∀ ε > 0, ∃ N, ∀ n ≥ N, ‖↑f n‖ ≤ ε} → c • x ∈ {f | ∀ ε > 0, ∃ N, ∀ n ≥ N, ‖↑f n‖ ≤ ε}

∀ (E : ℕ → Type u_1) [inst : (i : ℕ) → NormedAddCommGroup (E i)] {a b : ↥(lp E ⊤)},
  a ∈ {f | ∀ ε > 0, ∃ N, ∀ n ≥ N, ‖↑f n‖ ≤ ε} →
    b ∈ {f | ∀ ε > 0, ∃ N, ∀ n ≥ N, ‖↑f n‖ ≤ ε} → a + b ∈ {f | ∀ ε > 0, ∃ N, ∀ n ≥ N, ‖↑f n‖ ≤ ε}
